231→        const file = e.target.files[0];
232→        if(file){
233→            setImageFile(file)
234→            const reader = new FileReader();
235→            reader.onloadend = () =>{
236→                setProfilePreview(reader.result)
237→            }
238→            reader.readAsDataURL(file)
239→        }
