242→    const slugifyForUsername = (val) =>
243→        String(val || '').toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
244→
245→    const handleNameChangeForSetup = (e) => {
246→        const newName = e.target.value;
247→        setName(newName);
248→        // Auto-suggest username from name if user hasn't manually edited username
249→        if (!setupUsername || setupUsername === slugifyForUsername(name)) {
250→            const suggested = slugifyForUsername(newName);
251→            setSetupUsername(suggested);
252→            checkUsernameDebounced(suggested);
253→        }
254→    };
255→
256→    const handleUsernameChange = (e) => {
257→        const raw = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '');
258→        setSetupUsername(raw);
259→        checkUsernameDebounced(raw);
260→    };
261→
262→    const checkUsernameDebounced = (uname) => {
263→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
264→        if (!uname || uname.length < 3) {
265→            setUsernameAvailable(null);
266→            return;
267→        }
268→        setUsernameChecking(true);
269→        usernameCheckTimer.current = setTimeout(async () => {
270→            try {
271→                const result = await checkUsernameAvailability(uname);
272→                setUsernameAvailable(result.available);
273→            } catch {
274→                setUsernameAvailable(null);
275→            } finally {
276→                setUsernameChecking(false);
277→            }
278→        }, 400);
279→    };
