294→    const handleSubmit = async(e) =>{
295→        e.stopPropagation();
296→        e.preventDefault();
297→        try {
298→            setUploadingUserData(true)
299→            const formdata = new FormData();
300→            if(imageFile){
301→                formdata.append('image', imageFile);
302→            }
303→            if(bio && name){
304→                formdata.append('name', name)
305→                formdata.append('bio', bio)
306→                if(setupUsername && setupUsername.length >= 3){
307→                    formdata.append('username', setupUsername)
308→                }
309→            }
