.streak-badge {
    display: inline-flex;
    align-items: center;
    gap: 2px;
    font-size: 12px;
    font-weight: 600;
    line-height: 1;
    vertical-align: middle;
    margin-left: 4px;
}

.streak-flame-icon {
    flex-shrink: 0;
}

.streak-count {
    font-variant-numeric: tabular-nums;
}

/* Ember tier: 1-6 days */
.streak-ember .streak-flame-icon {
    fill: #f59e0b;
    filter: drop-shadow(0 0 2px rgba(245, 158, 11, 0.4));
}
.streak-ember .streak-count {
    color: #f59e0b;
}

/* Burning tier: 7-13 days */
.streak-burning .streak-flame-icon {
    fill: #f97316;
    filter: drop-shadow(0 0 4px rgba(249, 115, 22, 0.5));
}
.streak-burning .streak-count {
    color: #f97316;
}

/* Blazing tier: 14-29 days */
.streak-blazing .streak-flame-icon {
    fill: #ef4444;
    filter: drop-shadow(0 0 6px rgba(239, 68, 68, 0.6));
    animation: streak-glow 2s ease-in-out infinite;
}
.streak-blazing .streak-count {
    color: #ef4444;
}

/* Inferno tier: 30-99 days */
.streak-inferno .streak-flame-icon {
    fill: #ef4444;
    filter: drop-shadow(0 0 8px rgba(239, 68, 68, 0.7));
    animation: streak-pulse 1.5s ease-in-out infinite;
}
.streak-inferno .streak-count {
    color: #ef4444;
}

/* Legendary tier: 100+ days */
.streak-legendary .streak-flame-icon {
    fill: #eab308;
    filter: drop-shadow(0 0 10px rgba(234, 179, 8, 0.8)) drop-shadow(0 0 20px rgba(234, 179, 8, 0.4));
    animation: streak-sparkle 2s ease-in-out infinite;
}
.streak-legendary .streak-count {
    color: #eab308;
    text-shadow: 0 0 6px rgba(234, 179, 8, 0.5);
}

@keyframes streak-glow {
    0%, 100% { filter: drop-shadow(0 0 4px rgba(239, 68, 68, 0.4)); }
    50% { filter: drop-shadow(0 0 8px rgba(239, 68, 68, 0.7)); }
}

@keyframes streak-pulse {
    0%, 100% { transform: scale(1); filter: drop-shadow(0 0 6px rgba(239, 68, 68, 0.5)); }
    50% { transform: scale(1.1); filter: drop-shadow(0 0 10px rgba(239, 68, 68, 0.8)); }
}

@keyframes streak-sparkle {
    0%, 100% {
        transform: scale(1);
        filter: drop-shadow(0 0 8px rgba(234, 179, 8, 0.6)) drop-shadow(0 0 16px rgba(234, 179, 8, 0.3));
    }
    25% { transform: scale(1.05); }
    50% {
        transform: scale(1.1);
        filter: drop-shadow(0 0 12px rgba(234, 179, 8, 0.9)) drop-shadow(0 0 24px rgba(234, 179, 8, 0.5));
    }
    75% { transform: scale(1.05); }
}

/* Freeze indicator */
.streak-freeze-indicator {
    color: #60a5fa;
    opacity: 0.7;
    flex-shrink: 0;
    margin-left: 1px;
}

/* Progress bar toward next milestone */
.streak-progress-hint {
    display: inline-flex;
    align-items: center;
    margin-left: 4px;
}

.streak-progress-bar-track {
    display: inline-block;
    width: 40px;
    height: 3px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 2px;
    overflow: hidden;
}

.streak-progress-bar-fill {
    display: block;
    height: 100%;
    background: currentColor;
    border-radius: 2px;
    transition: width 0.3s ease;
}

