        if (result?.streakResult?.freezeUsed) responsePayload.freezeUsed = true;

        // TODO: REMOVE AFTER TESTING — force milestone + freeze toast
        responsePayload.milestone = 30;
        responsePayload.freezeUsed = true;
        return res.status(200).json(responsePayload);
    } catch (error) {
        console.error('failed to upload content:', error);
        return res.status(500).json({error: 'failed to upload content!'})
