    //     return() => {
    //         document.removeEventListener('scroll', handleScroll, true);
    //         clearTimeout(scrollRefTimeOut.current)
    //     }
    // }, [])

    useEffect(() => {
        const getUserData = async() => {   
            const userData = await checkUser(session?.user.id)   
            if(userData){
                const exist = userData.exist;
                if(!exist){
                    setShowProfileEditor(true)
                }
            }
        }
        if(session && !loading){
            getUserData();
        }

    },[session, loading])

    // Listen for streak milestone events from editors
    useEffect(() => {
        const handleMilestone = (e) => {
            console.log('[DEBUG] streak-milestone event received:', e.detail);
            setPendingMilestone(e.detail?.milestone);
        };
        const handleFreeze = () => {
            console.log('[DEBUG] streak-freeze-used event received');
            setShowFreezeUsedToast(true);
        };
        window.addEventListener('streak-milestone', handleMilestone);
        window.addEventListener('streak-freeze-used', handleFreeze);
        return () => {
            window.removeEventListener('streak-milestone', handleMilestone);
            window.removeEventListener('streak-freeze-used', handleFreeze);
        };
    }, []);

    // Auto-dismiss freeze toast after 4 seconds
    useEffect(() => {
        if (!showFreezeUsedToast) return;
        const timer = setTimeout(() => setShowFreezeUsedToast(false), 4000);
        return () => clearTimeout(timer);
    }, [showFreezeUsedToast]);


    if(isLoading && !isGuest){
        return(
            <Loader/>
        )
    }

    return(
        <>
        {!isGuest && showWelcomeMessage && (
            <WelcomeMessage onClose={handleCloseWelcomeMessage}/>
        )}

        <AnimatePresence>
        {!isGuest && showEditor && (
            <Editor
                key={'main-editor'}
                onClose={handleCloseEditor}
                initialMode={editorLaunchConfig.initialMode}
                initialTitle={editorLaunchConfig.initialTitle}
                initialCanvasDoc={editorLaunchConfig.initialCanvasDoc}
                remixSource={editorLaunchConfig.remixSource}
                promptId={editorLaunchConfig.promptId}
                promptText={editorLaunchConfig.promptText}
            />
        )}

        {!isGuest && showOpinionEditor && (
            <OpinionEditor onClose={handleCloseOpiniionTextEditor}/>
        )}

        </AnimatePresence>

        {!isGuest && uploadingUserData && (
            <>
            <div className="uploading-bg">
                <BeatLoader loading={uploadingUserData} size={20} speedMultiplier={2}/>
            </div>
            </>
        )}

        <AnimatePresence>
        {!isGuest && showProfileEditor && (
        <div className="profile-editor-bg">

            <motion.div 
            className="profile-editor"
            initial={{scale: 0, opacity: 0}}
            animate={{scale: 1, opacity: 1, transition: {type: 'tween', duration: 0.3}}}
            exit={{
