 1→import React from 'react';
 2→import { useQuery } from '@tanstack/react-query';
 3→import { getTodaysPrompt, getPromptResponses } from '../../../API/Api';
 4→import './DailyPromptCard.css';
 5→
 6→const DailyPromptCard = ({ onWriteResponse }) => {
 7→    const { data: prompt, isLoading } = useQuery({
 8→        queryKey: ['todaysPrompt'],
 9→        queryFn: getTodaysPrompt,
10→        staleTime: 1000 * 60 * 30,
11→        refetchOnWindowFocus: false,
12→    });
13→
14→    const { data: responsesData } = useQuery({
15→        queryKey: ['promptResponses', prompt?.id],
16→        queryFn: () => getPromptResponses(prompt.id),
17→        enabled: !!prompt?.id,
18→        staleTime: 1000 * 60 * 5,
19→        refetchOnWindowFocus: false,
20→    });
21→
22→    if (isLoading || !prompt) return null;
23→
24→    const responseCount = responsesData?.count || 0;
25→    const avatars = (responsesData?.responses || []).slice(0, 5);
26→
27→    return (
28→        <div className="daily-prompt-card">
29→            <div className="daily-prompt-header">
30→                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 -960 960 960" fill="currentColor" className="daily-prompt-icon">
31→                    <path d="M480-80q-26 0-47-12.5T400-126q-33 0-56.5-23.5T320-206v-142q-59-39-94.5-103T190-590q0-121 84.5-205.5T480-880q121 0 205.5 84.5T770-590q0 77-35.5 140T640-348v142q0 33-23.5 56.5T560-126q-12 21-33 33.5T480-80Zm-80-126h160v-36H400v36Zm0-76h160v-38H400v38Zm-8-118h58v-108l-88-88 42-42 76 76 76-76 42 42-88 88v108h58q54-26 88-76.5T690-590q0-88-61-149t-149-61q-88 0-149 61t-61 149q0 63 34 113.5t88 76.5Z"/>
32→                </svg>
33→                <span className="daily-prompt-label">Today's Prompt</span>
34→                {prompt.category && (
35→                    <span className="daily-prompt-category">{prompt.category}</span>
36→                )}
37→            </div>
38→            <p className="daily-prompt-text">{prompt.prompt_text}</p>
39→            <div className="daily-prompt-footer">
40→                <button
41→                    className="daily-prompt-write-btn"
42→                    onClick={() => onWriteResponse?.(prompt)}
43→                >
44→                    Write your take
45→                </button>
46→                {responseCount > 0 && (
47→                    <div className="daily-prompt-responses">
48→                        <div className="daily-prompt-avatars">
49→                            {avatars.map((r, i) => (
50→                                <img
51→                                    key={r.id}
52→                                    src={r.users?.image_url || '/assets/profile.jpg'}
53→                                    alt=""
54→                                    className="daily-prompt-avatar"
55→                                    style={{ zIndex: avatars.length - i }}
56→                                />
57→                            ))}
58→                        </div>
59→                        <span className="daily-prompt-count">
60→                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
61→                        </span>
62→                    </div>
63→                )}
64→            </div>
65→        </div>
66→    );
67→};
68→
69→export default DailyPromptCard;
