import React from 'react';

const PromptSection = ({ prompt, responsesData, onWriteResponse }) => {
    const responseCount = responsesData?.count || 0;
    const avatars = (responsesData?.responses || []).slice(0, 5);

    return (
        <div className="dashboard-prompt">
            <div className="dashboard-prompt-header">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 -960 960 960" fill="currentColor" className="dashboard-prompt-icon">
                    <path d="M480-80q-26 0-47-12.5T400-126q-33 0-56.5-23.5T320-206v-142q-59-39-94.5-103T190-590q0-121 84.5-205.5T480-880q121 0 205.5 84.5T770-590q0 77-35.5 140T640-348v142q0 33-23.5 56.5T560-126q-12 21-33 33.5T480-80Zm-80-126h160v-36H400v36Zm0-76h160v-38H400v38Zm-8-118h58v-108l-88-88 42-42 76 76 76-76 42 42-88 88v108h58q54-26 88-76.5T690-590q0-88-61-149t-149-61q-88 0-149 61t-61 149q0 63 34 113.5t88 76.5Z"/>
                </svg>
                <span className="dashboard-prompt-label">Today's Prompt</span>
                {prompt.category && (
                    <span className="dashboard-prompt-category">{prompt.category}</span>
                )}
            </div>
            <p className="dashboard-prompt-text">{prompt.prompt_text}</p>
            <div className="dashboard-prompt-footer">
                <button
                    className="dashboard-prompt-write-btn"
                    onClick={() => onWriteResponse?.(prompt)}
                >
                    Write your take <span style={{ marginLeft: '6px' }}>→</span>
                </button>
                {responseCount > 0 && (
                    <div className="dashboard-prompt-responses">
                        <div className="dashboard-prompt-avatars">
                            {avatars.map((r, i) => (
                                <img
                                    key={r.id}
                                    src={r.users?.image_url || '/assets/profile.jpg'}
                                    alt=""
                                    className="dashboard-prompt-avatar"
                                    style={{ zIndex: avatars.length - i }}
                                />
                            ))}
                        </div>
                        <span className="dashboard-prompt-count">
                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
                        </span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PromptSection;

